// Load and validate roster.yml. Throw if absent or invalid.
const fs = require('fs');
const yaml = require('js-yaml');
const path = process.env.ROSTER_CONFIG_PATH || '/data/roster.yml';
let roster;
try {
  roster = yaml.load(fs.readFileSync(path, 'utf8'));
} catch (e) {
  throw new Error('Roster Sync: cannot load roster.yml: ' + e.message);
}
if (!roster || !roster.team || !roster.team_lead) {
  throw new Error('Roster Sync: roster.yml missing required fields.');
}
// Build member list as individual items — one per member for SplitInBatches.
// Team lead is included as an active member.
const allMembers = [
  ...roster.team.map(m => ({ discord_id: m.discord_id, name: m.name, clockify_id: m.clockify_id || null, active: m.active !== false })),
  { discord_id: roster.team_lead.discord_id, name: roster.team_lead.name, clockify_id: null, active: true }
];
const memberCount = allMembers.length;
const teamLeadChannelId = roster.team_lead_channel_id;
// Return one item per member — SplitInBatches will iterate them.
// The team_lead_channel_id and member_count are carried in each item.
return allMembers.map(m => ({
  json: {
    discord_id: m.discord_id,
    name: m.name,
    clockify_id: m.clockify_id,
    active: m.active,
    team_lead_channel_id: teamLeadChannelId,
    member_count: memberCount
  }
}));

// After all members upserted, check if this is the last batch item.
// We only post the confirmation once — on the final item.
// SplitInBatches sets $runIndex (0-based) and $itemIndex.
// Use the member_count carried in each item to detect the final one.
const memberCount = $json.member_count;
const currentIndex = $itemIndex + 1;
if (currentIndex < memberCount) {
  return []; // Not the last member — continue without posting
}
return [{ json: { team_lead_channel_id: $json.team_lead_channel_id, member_count: memberCount } }];
